SourceCode.Declaration:
/// <summary>
/// Abstract base for channel handlers resolved through the SysExtension framework.
/// </summary>
public abstract class ConDemoChannelHandler
{
}

Method.Source:
/// <summary>
/// Describes the channel handled by this implementation.
/// </summary>
/// <returns>A label describing the channel.</returns>
public abstract str describe()
{
}

/// <summary>
/// Resolves the handler implementation decorated for the specified channel.
/// </summary>
/// <param name = "_channel">The channel to resolve a handler for.</param>
/// <returns>An instance of <c>ConDemoChannelHandler</c>; otherwise, null.</returns>
public static ConDemoChannelHandler construct(ConDemoChannelType _channel)
{
    ConDemoChannelHandler handler = SysExtensionAppClassFactory::getClassFromSysAttribute(
    classStr(ConDemoChannelHandler),
    new ConDemoChannelAttribute(_channel)) as ConDemoChannelHandler;

    return handler;
}
